INSERT INTO `strategies` (`id`, `sort_order`, `payload`, `created_at`, `updated_at`) VALUES ('st-2eac57ed', -1, '{"id": "st-2eac57ed", "name": "箱体蓄势放量突破策略", "score": 88, "period": "1H", "source": "ai", "enabled": true, "runtime": {"code": "def get_value(candle, key):\\n    if isinstance(candle, dict):\\n        return candle.get(key)\\n    return getattr(candle, key, None)\\n\\n\\ndef average(values):\\n    valid = [v for v in values if v is not None]\\n    if not valid:\\n        return 0\\n    return sum(valid) / len(valid)\\n\\n\\ndef check_signal(candles):\\n    if candles is None or len(candles) < 240:\\n        return False\\n\\n    recent_240 = candles[-240:]\\n    recent_10 = candles[-10:]\\n    recent_25 = candles[-25:]\\n    breakout_window = candles[-49:-1]\\n\\n    highs_240 = [get_value(c, ''high'') for c in recent_240]\\n    lows_240 = [get_value(c, ''low'') for c in recent_240]\\n    closes_10 = [get_value(c, ''close'') for c in recent_10]\\n    ma20_10 = [get_value(c, ''ma20'') for c in recent_10]\\n    volumes_25 = [get_value(c, ''volume'') for c in recent_25]\\n    breakout_highs = [get_value(c, ''high'') for c in breakout_window]\\n    latest_close = get_value(candles[-1], ''close'')\\n\\n    required_values = highs_240 + lows_240 + closes_10 + ma20_10 + volumes_25 + breakout_highs + [latest_close]\\n    if any(v is None for v in required_values):\\n        return False\\n    if any(v <= 0 for v in lows_240 + volumes_25):\\n        return False\\n\\n    range_compressed = (max(highs_240) / min(lows_240)) <= 1.30\\n    above_ma20_count = sum(1 for close, ma20 in zip(closes_10, ma20_10) if close > ma20)\\n    trend_confirmed = above_ma20_count / len(recent_10) >= 0.8\\n    avg_volume_24 = average(volumes_25[:-1])\\n    volume_breakout = avg_volume_24 > 0 and volumes_25[-1] >= avg_volume_24 * 3\\n    price_breakout = latest_close > max(breakout_highs)\\n\\n    return range_compressed and trend_confirmed and volume_breakout and price_breakout\\n", "version": 1, "language": "python", "aiAnalysis": ["这是一套偏趋势启动前段的筛选逻辑，核心思想是先找到价格长时间没有有效扩散、但内部逐步转强的阶段，再等待成交量突然放大来确认突破。这样做的好处是先用结构过滤噪音，再用行为确认方向，能够避免单独依赖某一个指标带来的误判。", "最近10天振幅小于30%代表市场此前处于相对收敛的箱体或平台区域，价格在有限范围内反复震荡，说明筹码交换较充分。如果后续真的出现向上突破，这类蓄势结构往往比无整理直接拉升更有延续观察价值。", "最近10根1小时K线大部分站上MA20，反映短线价格重心已经上移。这里并不是要求每一根都绝对强势，而是要求大多数收盘价位于均线上方，这样既保留趋势初期的弹性，也能避免对单根K线过度敏感。", "最近1小时成交量大于过去24小时均量3倍，是这套策略中最重要的确认条件之一。放量意味着突破行为不只是价格波动，还伴随成交活跃度明显提升，通常更能说明市场参与者开始集中表达方向性预期。", "这组参数适合用来发现整理后的启动信号，但并不保证每次放量都能形成持续趋势。实际使用时，建议结合历史样本回看不同振幅阈值、站上MA20比例和放量倍数的触发频率，观察信号是否过密或过稀，再决定是否微调参数。", "如果需要进一步增强策略稳定性，可以在后续版本中补充突破位置约束，例如要求最新收盘价接近或突破近阶段高点，或者要求MA20本身开始走平转上。这样能够让信号更聚焦于真正的结构突破，而不是普通反弹。"], "entrypoint": "check_signal", "structuredConditions": [{"title": "长期箱体震荡压缩", "parameters": ["统计范围：10天/240根", "振幅阈值：30%"], "description": "以 1 小时周期统计最近 10 天，也就是近 240 根 K 线的最高价与最低价区间，要求整体振幅小于 30%，用于识别前期充分整理、波动收敛的结构。"}, {"title": "短线价格站上 MA20", "parameters": ["观察根数：10根", "站上比例：至少80%"], "description": "检查最近 10 根 1 小时 K 线，要求大部分收盘价位于 MA20 上方，等价定义为至少 8 根收盘价高于 MA20，用于确认价格已经具备向上偏强特征。"}, {"title": "最近1小时放量突破", "parameters": ["均量周期：24根", "放量倍数：3倍"], "description": "要求最新一根 1 小时 K 线成交量大于此前 24 根 1 小时 K 线平均成交量的 3 倍，以确认突破阶段有明显增量资金参与。"}]}, "schedule": {"enabled": true, "lastError": "", "lastRunAt": "2026-06-01T07:15:12.639680+00:00", "lastStatus": "success", "intervalSeconds": 300}, "createdAt": "2026-05-31T18:43:46.627673+00:00", "conditions": ["前面长期箱体震荡，最近10天振幅小于30%", "最近10根1小时K线，大部分都在MA20上方", "最近1小时放量突破，成交量大于过去24小时均量3倍"], "description": "识别长期收敛震荡后，价格站稳 MA20 并以放量方式突破的趋势启动信号。", "lastTriggeredAt": "2026-06-01T07:15:12.639680+00:00", "todaySignalCount": 20}', '2026-05-31T18:43:46.634662+00:00', '2026-06-01T07:39:34.506881+00:00') ON DUPLICATE KEY UPDATE `sort_order`=VALUES(`sort_order`), `payload`=VALUES(`payload`), `created_at`=VALUES(`created_at`), `updated_at`=VALUES(`updated_at`);
