转上。这样能够让信号更聚焦于真正的结构突破，而不是普通反弹。"], "signalType": "strategy", "strategyId": "st-2eac57ed", "triggeredAt": "2026-06-01T07:15:12.639680+00:00", "strategyName": "箱体蓄势放量突破策略", "strengthGrade": "A"}', '2026-06-01T07:20:00.730736+00:00', '2026-06-01T07:20:00.730736+00:00') ON DUPLICATE KEY UPDATE `sort_order`=VALUES(`sort_order`), `payload`=VALUES(`payload`), `created_at`=VALUES(`created_at`), `updated_at`=VALUES(`updated_at`);
