: "2026-05-31T19:00:00+00:00", "close": 0.1841, "volume": 393653.7}, {"low": 0.184, "ma5": 0.18408, "high": 0.1862, "ma20": 0.18571, "ma60": 0.1866233333333333, "open": 0.1841, "time": "2026-05-31T20:00:00+00:00", "close": 0.1859, "volume": 301837.7}, {"low": 0.1857, "ma5": 0.18516, "high": 0.1879, "ma20": 0.185715, "ma60": 0.18666333333333332, "open": 0.186, "time": "2026-05-31T21:00:00+00:00", "close": 0.1879, "volume": 329419.4}, {"low": 0.1869, "ma5": 0.18604, "high": 0.1891, "ma20": 0.185745, "ma60": 0.186725, "open": 0.1879, "time": "2026-05-31T22:00:00+00:00", "close": 0.1884, "volume": 803866.2}, {"low": 0.1882, "ma5": 0.18728000000000003, "high": 0.1902, "ma20": 0.18586500000000003, "ma60": 0.1868216666666667, "open": 0.1885, "time": "2026-05-31T23:00:00+00:00", "close": 0.1901, "volume": 1675186.6}, {"low": 0.1896, "ma5": 0.1887, "high": 0.1926, "ma20": 0.186, "ma60": 0.1869666666666667, "open": 0.1902, "time": "2026-06-01T00:00:00+00:00", "close": 0.1912, "volume": 1250096.5}, {"low": 0.1891, "ma5": 0.18938, "high": 0.1914, "ma20": 0.18611, "ma60": 0.18707166666666664, "open": 0.1912, "time": "2026-06-01T01:00:00+00:00", "close": 0.1893, "volume": 1198733.6}, {"low": 0.1883, "ma5": 0.19074, "high": 0.1951, "ma20": 0.186505, "ma60": 0.1872666666666666, "open": 0.1892, "time": "2026-06-01T02:00:00+00:00", "close": 0.1947, "volume": 1807473.6}, {"low": 0.1947, "ma5": 0.19278, "high": 0.1995, "ma20": 0.187135, "ma60": 0.18744166666666665, "open": 0.1948, "time": "2026-06-01T03:00:00+00:00", "close": 0.1986, "volume": 2064733.4}], "summary": "THETAUSDT 命中策略：箱体蓄势放量突破策略", "analysis": ["这是一套偏趋势启动前段的筛选逻辑，核心思想是先找到价格长时间没有有效扩散、但内部逐步转强的阶段，再等待成交量突然放大来确认突破。这样做的好处是先用结构过滤噪音，再用行为确认方向，能够避免单独依赖某一个指标带来的误判。", "最近10天振幅小于30%代表市场此前处于相对收敛的箱体或平台区域，价格在有限范围内反复震荡，说明筹码交换较充分。如果后续真的出现向上突破，这类蓄势结构往往比无整理直接拉升更有延续观察价值。", "最近10根1小时K线大部分站上MA20，反映短线价格重心已经上移。这里并不是要求每一根都绝对强势，而是要求大多数收盘价位于均线上方，这样既保留趋势初期的弹性，也能避免对单根K线过度敏感。", "最近1小时成交量大于过去24小时均量3倍，是这套策略中最重要的确认条件之一。放量意味着突破行为不只是价格波动，还伴随成交活跃度明显提升，通常更能说明市场参与者开始集中表达方向性预期。", "这组参数适合用来发现整理后的启动信号，但并不保证每次放量都能形成持续趋势。实际使用时，建议结合历史样本回看不同振幅阈值、站上MA20比例和放量倍数的触发频率，观察信号是否过密或过稀，再决定是否微调参数。", "如果需要进一步增强策略稳定性，可以在后续版本中补充突破位置约束，例如要求最新收盘价接近或突破近阶段高点，或者要求MA20本身开始走平转上。这样能够让信号更聚焦于真正的结构突破，而不是普通反弹。"], "signalType": "strategy", "strategyId": "st-2eac57ed", "triggeredAt": "2026-06-01T04:17:22.894932+00:00", "strategyName": "箱体蓄势放量突破策略", "strengthGrade": "A"}', '2026-06-01T04:22:12.245520+00:00', '2026-06-01T04:22:12.245520+00:00') ON DUPLICATE KEY UPDATE `sort_order`=VALUES(`sort_order`), `payload`=VALUES(`payload`), `created_at`=VALUES(`created_at`), `updated_at`=VALUES(`updated_at`);
