57ed", "triggeredAt": "2026-06-01T04:17:22.894932+00:00", "strategyName": "箱体蓄势放量突破策略", "strengthGrade": "A"}', '2026-06-01T04:17:29.581427+00:00', '2026-06-01T04:17:29.581427+00:00') ON DUPLICATE KEY UPDATE `sort_order`=VALUES(`sort_order`), `payload`=VALUES(`payload`), `created_at`=VALUES(`created_at`), `updated_at`=VALUES(`updated_at`);
