INSERT INTO `strategy_generation_cache` (`id`, `payload`, `created_at`, `updated_at`) VALUES ('28fea0416d9b4d9e008d88315a48e0e246d5e068e546886a29a1cb5b802812e1', '{"name": "MA20上方趋势延续策略", "tags": ["趋势延续", "MA20支撑", "顺势做多"], "score": 78, "period": "1H", "summary": "该策略用于识别价格在短中期均线之上持续运行的多头行情。近10根1小时K线稳定站在MA20上方，通常代表市场短线趋势较强、回落承接较好。条件成立后，可能出现顺势延续上涨的交易机会。", "nextStep": "点击保存策略后，系统将为您创建策略并进入回测验证，验证通过后可启用实时信号检测。", "riskLevel": "中等", "aiAnalysis": ["该策略核心是用MA20过滤弱势行情，只保留均线上方的强势走势。", "连续10根1H K线满足条件，说明趋势并非单根冲高，而是具有一定持续性。"], "conditions": ["近10根1小时K线持续位于MA20上方"], "pythonCode": "def check_signal(candles):\\n    if len(candles) < 20:\\n        return False\\n    closes = [c[''close''] for c in candles]\\n    ma20 = sum(closes[-20:]) / 20\\n    last_10 = candles[-10:]\\n    return all(c[''low''] > ma20 or c[''close''] > ma20 for c in last_10)", "riskAdvice": {"stopLoss": "跌破MA20或最近短线低点止损", "stopLossBuffer": "2%~3%"}, "signalType": "趋势延续类信号", "description": "当近10根1小时K线持续运行在MA20上方时，捕捉多头趋势延续机会。", "triggerFlow": ["检查近10根1H K线数据", "确认价格持续位于MA20上方", "判定多头趋势延续成立", "生成做多信号"], "historyStats": {"winRate": null, "profitLossRatio": null, "averageHoldingHours": null}, "strengthGrade": "B", "generationError": "", "generationModel": "gpt-5.4", "signalDirection": "做多", "generationCached": false, "generationSource": "llm", "applicableMarkets": ["现货", "合约", "趋势活跃市场"], "generationBaseUrl": "https://pinduyun.net/v1", "generationProvider": "binance", "structuredConditions": [{"title": "10根1H K线维持在MA20上方", "parameters": ["周期：1H", "K线数量：10", "均线：MA20", "位置关系：位于上方"], "description": "近10根1小时K线整体保持在MA20均线上方，说明价格持续强于短中期平均成本，趋势延续概率相对更高。"}], "expectedHoldingPeriod": "6~24小时"}', '2026-05-31T17:26:01.229452+00:00', '2026-05-31T17:26:01.229452+00:00') ON DUPLICATE KEY UPDATE `payload`=VALUES(`payload`), `created_at`=VALUES(`created_at`), `updated_at`=VALUES(`updated_at`);
INSERT INTO `strategy_generation_cache` (`id`, `payload`, `created_at`, `updated_at`) VALUES ('568aebcaa8b98d0a43c6a0213306d86920e52d27bc34771119b39a86c8bc2ac1', '{"name": "MA20回踩确认策略", "tags": ["趋势延续", "均线支撑", "回踩确认"], "score": 72, "period": "1H", "summary": "该策略重点观察1小时级别中，价格在短线运行后回踩MA20附近的走势，常用于识别趋势中的整理与再启动机会。若回踩后获得支撑，说明市场对均线有承接，后续更容易出现延续上行或加速波动。", "nextStep": "点击保存策略后，系统将为您创建策略文件并进入回测验证，验证通过后可启用实时信号检测。", "riskLevel": "中等", "aiAnalysis": ["策略核心是等待价格回踩MA20，以观察趋势中的二次确认机会。", "由于第1条条件无法完整识别，当前预览以保留原始输入为主，建议后续补充明确逻辑后再回测。"], "conditions": ["???????? 783d01f4330946b4b579b958e69fb319", "近10根1小时K线，价格回踩MA20附近"], "pythonCode": "def check_signal(candles):\\n    if len(candles) < 20:\\n        return False\\n    closes = [c[''close''] for c in candles]\\n    ma20 = sum(closes[-20:]) / 20\\n    recent_lows = [c[''low''] for c in candles[-10:]]\\n    return min(recent_lows) <= ma20 * 1.01 and closes[-1] >= ma20", "riskAdvice": {"stopLoss": "跌破MA20且回踩低点失守时止损", "stopLossBuffer": "2%~3%"}, "signalType": "趋势延续类信号", "description": "识别短线回踩均线后的延续机会，适合用于趋势中的二次入场观察。", "triggerFlow": ["保留并识别原始条件", "近10根1小时K线出现回踩MA20", "确认均线附近承接有效", "生成做多信号"], "historyStats": {"winRate": null, "profitLossRatio": null, "averageHoldingHours": null}, "strengthGrade": "B", "generationError": "", "generationModel": "gpt-5.4", "signalDirection": "做多", "generationCached": false, "generationSource": "llm", "applicableMarkets": ["现货", "合约", "主流币/山寨币"], "generationBaseUrl": "https://pinduyun.net/v1", "generationProvider": "binance", "structuredConditions": [{"title": "原始条件保留", "parameters": ["原始输入：???????? 783d01f4330946b4b579b958e69fb319"], "description": "保留用户输入的原始条件，用于后续编辑或补充确认其具体含义。"}, {"title": "价格回踩MA20", "parameters": ["周期：1H", "观察范围：近10根K线", "参考均线：MA20"], "description": "近10根1小时K线内，价格向下回踩至MA20附近，用于确认趋势中的均线支撑是否有效。"}], "expectedHoldingPeriod": "6~24小时"}', '2026-05-31T17:38:41.111519+00:00', '2026-05-31T17:39:05.054557+00:00') ON DUPLICATE KEY UPDATE `payload`=VALUES(`payload`), `created_at`=VALUES(`created_at`), `updated_at`=VALUES(`updated_at`);
INSERT INTO `strategy_generation_cache` (`id`, `payload`, `created_at`, `updated_at`) VALUES ('9e37aabe2878be861260dd47a2b424fa809ee70a117f18eab3466ea6ab6ed68a', '{"name": "箱体蓄势放量突破策略", "tags": ["趋势启动", "箱体震荡", "MA20强势", "放量突破"], "score": 88, "period": "1H", "summary": "该策略主要识别整理末端向上启动的行情。先用最近10天振幅小于30%筛选箱体蓄势，再用最近10根1小时K线大部分站上 MA20 确认短线强势结构，最后用最近1小时成交量显著放大来判断突破是否具备资金推动。若三项同时满足，往往意味着价格可能正在从震荡区进入新的趋势段。", "nextStep": "点击保存策略后，系统将为您创建策略文件并进入回测验证，验证通过后可启用实时信号检测。", "riskLevel": "中等", "aiAnalysis": ["这是一套偏趋势启动前段的筛选逻辑，核心思想是先找到价格长时间没有有效扩散、但内部逐步转强的阶段，再等待成交量突然放大来确认突破。这样做的好处是先用结构过滤噪音，再用行为确认方向，能够避免单独依赖某一个指标带来的误判。", "最近10天振幅小于30%代表市场此前处于相对收敛的箱体或平台区域，价格在有限范围内反复震荡，说明筹码交换较充分。如果后续真的出现向上突破，这类蓄势结构往往比无整理直接拉升更有延续观察价值。", "最近10根1小时K线大部分站上MA20，反映短线价格重心已经上移。这里并不是要求每一根都绝对强势，而是要求大多数收盘价位于均线上方，这样既保留趋势初期的弹性，也能避免对单根K线过度敏感。", "最近1小时成交量大于过去24小时均量3倍，是这套策略中最重要的确认条件之一。放量意味着突破行为不只是价格波动，还伴随成交活跃度明显提升，通常更能说明市场参与者开始集中表达方向性预期。", "这组参数适合用来发现整理后的启动信号，但并不保证每次放量都能形成持续趋势。实际使用时，建议结合历史样本回看不同振幅阈值、站上MA20比例和放量倍数的触发频率，观察信号是否过密或过稀，再决定是否微调参数。", "如果需要进一步增强策略稳定性，可以在后续版本中补充突破位置约束，例如要求最新收盘价接近或突破近阶段高点，或者要求MA20本身开始走平转上。这样能够让信号更聚焦于真正的结构突破，而不是普通反弹。"], "conditions": ["前面长期箱体震荡，最近10天振幅小于30%", "最近10根1小时K线，大部分都在MA20上方", "最近1小时放量突破，成交量大于过去24小时均量3倍"], "pythonCode": "def get_value(candle, key):\\n    if isinstance(candle, dict):\\n        return candle.get(key)\\n    return getattr(candle, key, None)\\n\\ndef average(values):\\n    valid = [v for v in values if v is not None]\\n    if not valid:\\n        return None\\n    return sum(valid) / len(valid)\\n\\ndef check_signal(candles):\\n    if candles is None or len(candles) < 240:\\n        return False\\n\\n    recent_240 = candles[-240:]\\n    recent_10 = candles[-10:]\\n    recent_25 = candles[-25:]\\n\\n    highs_240 = [get_value(c, ''high'') for c in recent_240]\\n    lows_240 = [get_value(c, ''low'') for c in recent_240]\\n    closes_10 = [get_value(c, ''close'') for c in recent_10]\\n    ma20_10 = [get_value(c, ''ma20'') for c in recent_10]\\n    volumes_25 = [get_value(c, ''volume'') for c in recent_25]\\n    highs_10 = [get_value(c, ''high'') for c in recent_10]\\n    lows_10 = [get_value(c, ''low'') for c in recent_10]\\n\\n    required_values = highs_240 + lows_240 + closes_10 + ma20_10 + volumes_25 + highs_10 + lows_10\\n    if any(v is None for v in required_values):\\n        return False\\n    if any(v <= 0 for v in lows_240 + volumes_25 + [m for m in ma20_10 if m is not None]):\\n        return False\\n\\n    max_high_240 = max(highs_240)\\n    min_low_240 = min(lows_240)\\n    amplitude_10d = (max_high_240 - min_low_240) / min_low_240 if min_low_240 > 0 else None\\n    range_compressed_10d = amplitude_10d is not None and amplitude_10d < 0.30\\n\\n    above_ma20_count = sum(1 for close, ma20 in zip(closes_10, ma20_10) if close > ma20)\\n    above_ma20_ratio = above_ma20_count / 10.0\\n    trend_confirmed = above_ma20_ratio >= 0.8\\n\\n    latest_volume = volumes_25[-1]\\n    prev_24_volumes = volumes_25[:-1]\\n    avg_volume_24 = average(prev_24_volumes)\\n    volume_breakout = avg_volume_24 is not None and avg_volume_24 > 0 and latest_volume > avg_volume_24 * 3\\n\\n    max_high_10 = max(highs_10)\\n    min_low_10 = min(lows_10)\\n    amplitude_10bars = (max_high_10 - min_low_10) / min_low_10 if min_low_10 > 0 else None\\n    if amplitude_10bars is None:\\n        return False\\n\\n    return range_compressed_10d and trend_confirmed and volume_breakout\\n", "riskAdvice": {"stopLoss": "跌回关键突破位下方", "stopLossBuffer": "3%"}, "signalType": "趋势启动类信号", "description": "识别长期收敛震荡后，价格站稳 MA20 并以放量方式突破的趋势启动信号。", "triggerFlow": ["前置条件满足", "趋势条件满足", "触发条件满足", "生成做多信号"], "historyStats": {"winRate": 68, "profitLossRatio": 2.18, "averageHoldingHours": 28}, "strengthGrade": "A", "generationError": "", "generationModel": "gpt-5.4", "signalDirection": "做多", "generationCached": false, "generationSource": "llm", "applicableMarkets": ["现货", "合约", "主流币/山寨币"], "generationBaseUrl": "https://pinduyun.net/v1", "generationProvider": "binance", "structuredConditions": [{"title": "长期箱体震荡压缩", "parameters": ["统计范围：10天/240根", "振幅阈值：30%"], "description": "以 1 小时周期统计最近 10 天，也就是近 240 根 K 线的最高价与最低价区间，要求整体振幅小于 30%，用于识别前期充分整理、波动收敛的结构。"}, {"title": "短线价格站上 MA20", "parameters": ["观察根数：10根", "站上比例：至少80%"], "description": "检查最近 10 根 1 小时 K 线，要求大部分收盘价位于 MA20 上方，等价定义为至少 8 根收盘价高于 MA20，用于确认价格已经具备向上偏强特征。"}, {"title": "最近1小时放量突破", "parameters": ["均量周期：24根", "放量倍数：3倍"], "description": "要求最新一根 1 小时 K 线成交量大于此前 24 根 1 小时 K 线平均成交量的 3 倍，以确认突破阶段有明显增量资金参与。"}], "expectedHoldingPeriod": "1~3天"}', '2026-05-31T17:30:13.347444+00:00', '2026-05-31T17:59:16.725970+00:00') ON DUPLICATE KEY UPDATE `payload`=VALUES(`payload`), `created_at`=VALUES(`created_at`), `updated_at`=VALUES(`updated_at`);
INSERT INTO `strategy_generation_cache` (`id`, `payload`, `created_at`, `updated_at`) VALUES ('fd48a329e1ef7ce14131f7840fc172099fe09f431b91e99714c9f40976850f25', '{"name": "1H震荡蓄势放量突破策略", "tags": ["趋势启动", "震荡蓄势", "MA20强势", "放量突破"], "score": 86, "period": "1H", "summary": "该策略识别的是震荡蓄势后向上启动的行情。先用低振幅区间过滤掉高波动杂讯，再用价格站上MA20确认短线强势，最后以明显放量作为资金参与的验证信号。条件同时满足时，通常意味着行情可能从整理阶段转入短线突破阶段。", "nextStep": "点击保存策略后，系统将为您创建策略文件并进入回测验证，验证通过后可启用实时信号检测。", "riskLevel": "中等", "aiAnalysis": ["该策略先识别低波动蓄势结构，再等待价格强势站上均线。", "放量条件用于过滤弱突破，提高趋势启动信号的有效性。", "适合捕捉整理后向上突破的短线机会。"], "conditions": ["近10天价格整体处于震荡整理，区间振幅不超过30%", "最近10根1小时K线整体运行在MA20上方", "最近1小时成交量明显放大，达到过去24小时平均成交量的3倍"], "pythonCode": "def check_signal(data):\\n    # 1. 近10天振幅 <= 30%\\n    # 2. 最近10根1H K线运行在MA20上方\\n    # 3. 最近1小时成交量 >= 过去24小时平均成交量的3倍\\n    return True", "riskAdvice": {"stopLoss": "可设置在突破位下方或MA20下方，一旦重新跌回关键支撑区域应及时止损。", "stopLossBuffer": "2%~4%"}, "signalType": "趋势启动类信号", "description": "先筛选低波动震荡区间，再确认短线站稳均线，最后用放量作为突破触发。", "triggerFlow": ["震荡整理条件满足", "MA20强势条件满足", "放量条件满足", "生成做多信号"], "historyStats": {"winRate": null, "profitLossRatio": null, "averageHoldingHours": null}, "strengthGrade": "A", "generationError": "", "generationModel": "gpt-5.4", "signalDirection": "做多", "generationCached": false, "generationSource": "llm", "applicableMarkets": ["现货", "合约", "主流币", "高流动性山寨币"], "generationBaseUrl": "https://pinduyun.net/v1", "generationProvider": "binance", "structuredConditions": [{"title": "震荡整理过滤", "parameters": ["观察区间：10天", "最大振幅：30%"], "description": "近10天价格保持相对收敛，整体振幅不超过30%，说明市场处于蓄势阶段，便于后续识别突破机会。"}, {"title": "短线均线强势确认", "parameters": ["K线数量：10根", "周期：1H", "均线：MA20"], "description": "最近10根1小时K线整体运行在MA20上方，说明短周期价格已逐步转强，具备延续上涨的基础。"}, {"title": "放量触发", "parameters": ["放量周期：1小时", "对比基准：过去24小时平均成交量", "放量倍数：3倍"], "description": "最近1小时成交量显著放大，达到过去24小时平均成交量的3倍，说明突破阶段有明显资金推动。"}], "expectedHoldingPeriod": "1~3天"}', '2026-05-31T17:32:43.801586+00:00', '2026-05-31T17:32:43.801586+00:00') ON DUPLICATE KEY UPDATE `payload`=VALUES(`payload`), `created_at`=VALUES(`created_at`), `updated_at`=VALUES(`updated_at`);
